export function getBusinessType(code: string): BusinessTypeInfo {
  return BUSINESS_TYPES.find((b) => b.code === code) || BUSINESS_TYPES[BUSINESS_TYPES.length - 1];
}

export const BUSINESS_TYPE_CODES: BusinessType[] = BUSINESS_TYPES.map((b) => b.code);

